function colToA1(colIndex1Based) {
  let n = colIndex1Based;
  let out = '';
  while (n > 0) {
    const m = (n - 1) % 26;
    out = String.fromCharCode(65 + m) + out;
    n = Math.floor((n - 1) / 26);
  }
  return out;
}

function normalizeHeader(value) {
  return String(value || '').replace(/[^A-Za-z0-9]/g, '').toUpperCase();
}

const sheet = $('Webhook Read Google Sheet').first().json || {};
const values = sheet.values || [];
const sheetName = $('Set Credentials').first().json['✅SHEET_NAME'];

const headerRow = values[0] || [];
const skuCol = headerRow.findIndex((cell) => normalizeHeader(cell) === 'SKU');
const targetCol = headerRow.findIndex((cell) => normalizeHeader(cell) === 'FBAFEE');

if (skuCol === -1 || targetCol === -1) {
  throw new Error('Could not find SKU and FBA_FEE columns');
}

const targetColA1 = colToA1(targetCol + 1);
const data = [];
for (let i = 1; i < values.length; i++) {
  const row = values[i] || [];
  const sku = String(row[skuCol] || '').trim();
  if (!sku || /^SKU$/i.test(sku) || /^IMG$/i.test(sku) || /_TOTALS$/i.test(sku)) continue;
  data.push({
    range: `${sheetName}!${targetColA1}${i + 1}`,
    values: [['']],
  });
}

return [{ json: { valueInputOption: 'USER_ENTERED', data } }];

function toNumber(value) {
  if (value === null || value === undefined || value === '') return 0;
  const n = Number(String(value).replace(/[$,%\s,]/g, ''));
  return Number.isFinite(n) ? n : 0;
}
const sheet = $input.first().json || {};
const values = sheet.values || [];
let headerRowIdx = -1;
let skuCol = -1;
for (let i = 0; i < Math.min(values.length, 12); i++) {
  const row = values[i] || [];
  const foundSkuCol = row.findIndex((c) => String(c).trim().toUpperCase() === 'SKU');
  if (foundSkuCol !== -1) {
    headerRowIdx = i;
    skuCol = foundSkuCol;
    break;
  }
}
if (headerRowIdx === -1 || skuCol === -1) throw new Error('Could not find SKU header column');
const items = [];
for (let i = headerRowIdx + 1; i < values.length; i++) {
  const row = values[i] || [];
  const sku = String(row[skuCol] || '').trim();
  if (!sku || /^SKU$/i.test(sku) || /^IMG$/i.test(sku) || /_TOTALS$/i.test(sku)) continue;
  const listingPrice = toNumber(row[2] || 0) || 1;
  const unitsSold = toNumber(row[8] || 0);
  items.push({ json: { rowNumber: i + 1, sku, listingPrice, unitsSold } });
}
return items;

function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function normalizePayload(payload) {
  let current = payload;
  if (typeof current === 'string') {
    try { current = JSON.parse(current); } catch { return {}; }
  }
  if (current && typeof current === 'object' && typeof current.body === 'string') {
    try { current = JSON.parse(current.body); } catch {}
  } else if (current && typeof current === 'object' && current.body && typeof current.body === 'object') {
    current = current.body;
  }
  return current && typeof current === 'object' ? current : {};
}

function amountOf(value) {
  if (!value || typeof value !== 'object') return 0;
  const amount = Number(value.Amount ?? value.amount ?? 0);
  return Number.isFinite(amount) ? amount : 0;
}

function collectFeeDetails(container, acc) {
  if (!container || typeof container !== 'object') return;
  if (Array.isArray(container)) {
    for (const item of container) collectFeeDetails(item, acc);
    return;
  }
  if (container.FeeType || container.feeType) acc.push(container);
  for (const child of Object.values(container)) collectFeeDetails(child, acc);
}

function getPerUnitFulfillmentFee(rawPayload) {
  const payload = normalizePayload(rawPayload);
  const feeRoot = payload.payload?.FeesEstimateResult?.FeesEstimate || payload.FeesEstimateResult?.FeesEstimate || payload.payload?.feesEstimateResult?.feesEstimate || payload.feesEstimateResult?.feesEstimate || payload;
  const directList = feeRoot.FeeDetailList || feeRoot.feeDetailList || [];
  const details = [];
  collectFeeDetails(directList, details);
  if (!details.length) collectFeeDetails(feeRoot, details);
  let total = 0;
  for (const detail of details) {
    const type = String(detail.FeeType || detail.feeType || '').toLowerCase();
    if (!type) continue;
    if (type === 'fbafees') {
      const top = amountOf(detail.FinalFee || detail.finalFee || detail.FeeAmount || detail.feeAmount);
      if (top > 0) return Number(top.toFixed(2));
    }
    const isFulfillment = type.includes('fulfillment') || type.includes('pickandpack') || type.includes('weight') || type.includes('handling') || type.includes('fba');
    const exclude = type.includes('referral') || type.includes('closing') || type.includes('commission') || type.includes('storage');
    if (!isFulfillment || exclude) continue;
    total += amountOf(detail.FinalFee || detail.finalFee || detail.FeeAmount || detail.feeAmount);
  }
  return Number(total.toFixed(2));
}

const token = $('Set Credentials').first().json.AMAZON_ACCESS_TOKEN;
const items = $input.all();
const output = [];
for (let index = 0; index < items.length; index++) {
  const current = items[index].json || {};
  const sku = String(current.sku || '').trim();
  if (!sku) continue;
  const body = {
    FeesEstimateRequest: {
      MarketplaceId: $('Set Credentials').first().json['✅AMAZON_MARKETPLACE_ID'],
      IsAmazonFulfilled: true,
      Identifier: `${current.rowNumber}-${sku}`,
      PriceToEstimateFees: {
        ListingPrice: { CurrencyCode: 'USD', Amount: Number(current.listingPrice || 1) },
        Shipping: { CurrencyCode: 'USD', Amount: 0 },
      },
    },
  };
  let rawPayload = {};
  for (let attempt = 0; attempt < 5; attempt++) {
    try {
      rawPayload = await this.helpers.httpRequest({
        method: 'POST',
        url: `https://sellingpartnerapi-na.amazon.com/products/fees/v0/listings/${encodeURIComponent(sku)}/feesEstimate`,
        headers: {
          'x-amz-access-token': token,
          Accept: 'application/json',
          'Content-Type': 'application/json',
        },
        body,
        json: true,
      });
      break;
    } catch (error) {
      const statusCode = Number(error.statusCode || error.httpCode || error.response?.statusCode || 0);
      const isRetryable = statusCode === 429 || statusCode === 503 || String(error.message || '').toLowerCase().includes('too many requests');
      if (!isRetryable || attempt === 4) {
        rawPayload = { error: { message: error.message || 'Request failed', statusCode } };
        break;
      }
      await sleep(1500 * (attempt + 1));
    }
  }
  const perUnitFee = getPerUnitFulfillmentFee(rawPayload);
  const totalFee = Number((perUnitFee * Number(current.unitsSold || 0) * -1).toFixed(2));
  output.push({
    json: {
      rowNumber: current.rowNumber,
      sku,
      perUnitFee,
      unitsSold: current.unitsSold || 0,
      totalFee,
      debugRawPayload: index < 2 ? rawPayload : undefined,
      debugNormalizedPayload: index < 2 ? normalizePayload(rawPayload) : undefined,
      debugRequestBody: index < 2 ? body : undefined,
    },
  });
  if (index < items.length - 1) await sleep(1300);
}
return output;
